import { agentConfig } from '@mastra/core/agent'

export default agentConfig({
  model: 'anthropic/claude-sonnet-4-6',
})

import { readFile } from 'node:fs/promises'
import { createTool } from '@mastra/core/tools'
import { z } from 'zod'
import { resolveInWorkspace } from '../lib/workspace'

export default createTool({
  id: 'read_file',
  description: 'Reads a UTF-8 file from the workspace.',
  inputSchema: z.object({
    path: z.string(),
  }),
  execute: async (inputData) => {
    const { path: filePath } = inputData
    const content = await readFile(resolveInWorkspace(filePath), 'utf-8')
    return { content, path: filePath }
  },
})

import { mkdir, writeFile } from 'node:fs/promises'
import { dirname } from 'node:path'
import { createTool } from '@mastra/core/tools'
import { z } from 'zod'
import { resolveInWorkspace } from '../lib/workspace'

export default createTool({
  id: 'write_file',
  description: 'Writes (or overwrites) a UTF-8 file in the workspace.',
  inputSchema: z.object({
    path: z.string(),
    content: z.string(),
  }),
  execute: async (inputData) => {
    const { path: filePath, content } = inputData
    const target = resolveInWorkspace(filePath)
    await mkdir(dirname(target), { recursive: true })
    await writeFile(target, content, 'utf-8')
    return { bytes: content.length, path: filePath }
  },
})

import { exec } from 'node:child_process'
import { promisify } from 'node:util'
import { createTool } from '@mastra/core/tools'
import { z } from 'zod'
import { WORKSPACE } from '../lib/workspace'

const run = promisify(exec)

export default createTool({
  id: 'run_shell',
  description:
    'Runs a shell command inside the workspace directory and returns its stdout/stderr.',
  inputSchema: z.object({
    command: z.string(),
  }),
  execute: async (inputData) => {
    const { command } = inputData
    try {
      const { stdout, stderr } = await run(command, {
        cwd: WORKSPACE,
        timeout: 60_000,
      })
      return { stderr, stdout }
    } catch (error) {
      return { error: String(error) }
    }
  },
})

import { readFile, writeFile } from 'node:fs/promises'
import { createTool } from '@mastra/core/tools'
import { z } from 'zod'
import { resolveInWorkspace } from '../lib/workspace'

export default createTool({
  id: 'edit_file',
  description:
    'Replaces an exact string match in an existing file. Fails if oldContent is not found.',
  inputSchema: z.object({
    path: z.string().describe('Relative path to the file'),
    oldContent: z.string().describe('Exact string to find'),
    newContent: z.string().describe('String to replace it with'),
  }),
  execute: async (inputData) => {
    const { path: filePath, oldContent, newContent } = inputData
    const target = resolveInWorkspace(filePath)
    const content = await readFile(target, 'utf-8')
    if (!content.includes(oldContent)) {
      throw new Error(`oldContent not found in ${filePath}`)
    }
    await writeFile(target, content.replace(oldContent, newContent), 'utf-8')
    return { success: true, path: filePath }
  },
})

import { readdir, stat } from 'node:fs/promises'
import { createTool } from '@mastra/core/tools'
import { z } from 'zod'
import { resolveInWorkspace } from '../lib/workspace'

export default createTool({
  id: 'list_files',
  description: 'Lists files and subdirectories in a workspace directory.',
  inputSchema: z.object({
    dirPath: z
      .string()
      .optional()
      .describe('Relative directory path (defaults to workspace root)'),
  }),
  outputSchema: z.object({
    files: z.array(
      z.object({
        name: z.string(),
        type: z.enum(['file', 'directory']),
        size: z.number(),
      }),
    ),
  }),
  execute: async (inputData) => {
    const { dirPath = '.' } = inputData
    const target = resolveInWorkspace(dirPath)
    const entries = await readdir(target, { withFileTypes: true })
    const result = await Promise.all(
      entries.map(async (entry) => {
        const fullPath = `${target}/${entry.name}`
        const s = await stat(fullPath)
        return {
          name: entry.name,
          type: entry.isDirectory() ? 'directory' as const : 'file' as const,
          size: s.size,
        }
      }),
    )
    return { files: result }
  },
})

import { unlink } from 'node:fs/promises'
import { createTool } from '@mastra/core/tools'
import { z } from 'zod'
import { resolveInWorkspace } from '../lib/workspace'

export default createTool({
  id: 'delete_file',
  description: 'Deletes a file from the workspace.',
  inputSchema: z.object({
    path: z.string().describe('Relative path to the file to delete'),
  }),
  execute: async (inputData) => {
    const { path: filePath } = inputData
    const target = resolveInWorkspace(filePath)
    await unlink(target)
    return { success: true, path: filePath }
  },
})

import { readdir, readFile, stat } from 'node:fs/promises'
import { join, relative } from 'node:path'
import { createTool } from '@mastra/core/tools'
import { z } from 'zod'
import { resolveInWorkspace } from '../lib/workspace'

async function walk(dir: string): Promise<string[]> {
  const entries = await readdir(dir, { withFileTypes: true })
  const files: string[] = []
  for (const entry of entries) {
    const fullPath = join(dir, entry.name)
    if (entry.isDirectory()) {
      if (entry.name === 'node_modules' || entry.name === '.git') continue
      files.push(...(await walk(fullPath)))
    } else {
      files.push(fullPath)
    }
  }
  return files
}

export default createTool({
  id: 'grep',
  description: 'Searches for a regex pattern across files in the workspace.',
  inputSchema: z.object({
    pattern: z.string().describe('Regular expression pattern to search for'),
    dirPath: z
      .string()
      .optional()
      .describe('Relative directory to search in (defaults to workspace root)'),
  }),
  outputSchema: z.object({
    matches: z.array(
      z.object({
        file: z.string(),
        line: z.number(),
        content: z.string(),
      }),
    ),
  }),
  execute: async (inputData) => {
    const { pattern, dirPath = '.' } = inputData
    const root = resolveInWorkspace(dirPath)
    const re = new RegExp(pattern, 'gi')
    const files = await walk(root)
    const matches: Array<{ file: string; line: number; content: string }> = []
    for (const filePath of files) {
      try {
        const content = await readFile(filePath, 'utf-8')
        const lines = content.split('\n')
        for (let i = 0; i < lines.length; i++) {
          if (re.test(lines[i])) {
            matches.push({
              file: relative(process.cwd(), filePath),
              line: i + 1,
              content: lines[i],
            })
          }
          re.lastIndex = 0
        }
      } catch {
        // skip unreadable files
      }
    }
    return { matches }
  },
})

import path from 'node:path'

export const WORKSPACE = path.resolve(process.env.WORKSPACE_DIR ?? 'workspace')

export function resolveInWorkspace(relativePath: string): string {
  const resolved = path.resolve(WORKSPACE, relativePath)
  if (resolved !== WORKSPACE && !resolved.startsWith(WORKSPACE + path.sep)) {
    throw new Error(`Path escapes the workspace: ${relativePath}`)
  }
  return resolved
}
